const WEIGHTS = { veryOften: 60, medium: 25, rare: 12, veryRare: 3 };

function rollPrize() {
  const total = Object.values(WEIGHTS).reduce((a, b) => a + b, 0);
  let roll = Math.random() * total;
  let chosenRarity = "common";
  for (const [rarity, w] of Object.entries(WEIGHTS)) {
    if (roll < w) { chosenRarity = rarity; break; }
    roll -= w;
  }
  const pool = PRIZE_POOL.filter((p) => p.rarity === chosenRarity);
  return pool[Math.floor(Math.random() * pool.length)];
}

/* ------------------------------------------------------------------ */
/*  Server communication (auth + authoritative box opening)           */
/* ------------------------------------------------------------------ */
function getInitData() {
  try {
    const tg = window.Telegram?.WebApp;
    if (tg) return tg.initData || "";
  } catch (e) {}
  return "";
}

async function apiPost(path, body) {
  const res = await fetch(path, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok || !data.success) throw new Error(data.error || `HTTP ${res.status}`);
  return data;
}

async function syncWithServer() {
  try {
    const data = await apiPost("/api/auth", { initData: getInitData() });
    state.tickets = data.user.tickets;
    state.rpPoints = data.user.rpPoints;
    state.balance = data.user.rpPoints;
  } catch (e) {
    // Not running inside Telegram / server unreachable - fall back to local demo state.
    console.warn("Could not sync with server, using local demo state:", e.message);
  }

  try {
    const res = await fetch(`/api/missions/mine?initData=${encodeURIComponent(getInitData())}`);
    const data = await res.json();
    if (data.success) {
      state.selectedMissions = new Set(Object.keys(data.missions.selected || {}));
      state.confirmedMissions = new Set(Object.keys(data.missions.confirmed || {}));
    }
  } catch (e) {
    console.warn("Could not load missions state:", e.message);
  }

  try {
    const res = await fetch("/api/shop");
    const data = await res.json();
    if (data.success && Array.isArray(data.sections) && data.sections.length) {
      state.shopSections = data.sections;
    }
  } catch (e) {
    console.warn("Could not load shop catalog, using local fallback:", e.message);
  }
}

function haptic(style = "medium") {
  try {
    const tg = window.Telegram?.WebApp;
    if (tg?.HapticFeedback) {
      if (["success", "error", "warning"].includes(style)) {
        tg.HapticFeedback.notificationOccurred(style);
      } else {
        tg.HapticFeedback.impactOccurred(style);
      }
    }
  } catch (e) { /* not inside Telegram, ignore */ }
}

function icon(name, size = 18, color = "currentColor", extraAttrs = "") {
  return `<i data-lucide="${name}" style="width:${size}px;height:${size}px;color:${color};display:inline-block;vertical-align:middle;" ${extraAttrs}></i>`;
}


