function render() {
  const content = document.getElementById("content");
  if (state.page === "box") {
    content.innerHTML = renderMysteryBoxPage();
  } else if (state.page === "shop") {
    content.innerHTML = renderShopPage();
  } else if (state.page === "missions") {
    content.innerHTML = renderMissionsPage();
  } else if (state.page === "top") {
    content.innerHTML = renderTopPage();
  } else if (state.page === "more") {
    content.innerHTML = renderMorePage();
  } else if (state.page === "profile") {
    content.innerHTML = renderProfilePage();
  }

  document.getElementById("bottomNav").innerHTML = renderBottomNav();

  const modalContainer = document.getElementById("modalContainer");
  if (state.boxState === "revealed" && state.prize) {
    modalContainer.innerHTML = renderPrizeModal(state.prize);
  } else {
    modalContainer.innerHTML = "";
  }

  if (window.lucide) lucide.createIcons();
  attachHandlers();
}

