function renderChestIcon(selected) {
  const stateName = selected ? state.boxState : "idle";
  const cls = ["mb-box-img", `mb-box-img-${stateName}`, selected ? "mb-box-img-selected" : ""].join(" ");
  return `
    <div class="mb-box3d-scene">
      <img src="${CHEST_IMG_SRC}" alt="" class="${cls}" draggable="false" />
      <span class="mb-box3d-shadow"></span>
    </div>
  `;
}

function renderBurstParticles() {
  if (state.boxState !== "exploding") return "";
  let out = '<div class="mb-burst-wrap" aria-hidden="true">';
  for (let i = 0; i < 24; i++) {
    const angle = (Math.PI * 2 * i) / 24 + Math.random() * 0.3;
    const dist = 70 + Math.random() * 90;
    const x = Math.cos(angle) * dist;
    const y = Math.sin(angle) * dist;
    const size = 3 + Math.random() * 4;
    const delay = Math.random() * 0.15;
    out += `<span class="mb-burst-particle" style="--tx:${x}px;--ty:${y}px;width:${size}px;height:${size}px;animation-delay:${delay}s;"></span>`;
  }
  out += "</div>";
  return out;
}

function renderMysteryBoxPage() {
  const busy = ["selecting", "shaking", "exploding"].includes(state.boxState);
  const disabled = busy || state.tickets <= 0;
  const label =
    state.boxState === "selecting" ? "Обираємо бокс..." :
    state.boxState === "shaking" ? "Відкриваємо..." :
    state.boxState === "exploding" ? "Секунду..." :
    "ВІДКРИТИ MYSTERY BOX";

  let grid = "";
  for (let i = 0; i < 9; i++) {
    const isSelected = i === state.selectedIndex;
    const isCycling = isSelected && state.boxState === "selecting";
    const showArrows = isSelected && (state.boxState === "shaking" || state.boxState === "idle");
    grid += `
      <button class="mb-grid-cell ${isSelected ? "mb-grid-cell-active" : ""} ${isCycling ? "mb-grid-cell-cycling" : ""}"
              data-action="select" data-index="${i}" ${busy ? "disabled" : ""}>
        ${isSelected ? renderBurstParticles() : ""}
        ${showArrows ? '<span class="mb-select-arrow mb-select-arrow-top">▾</span>' : ""}
        <div class="mb-chest-wrap">${renderChestIcon(isSelected)}</div>
        ${showArrows ? '<span class="mb-select-arrow mb-select-arrow-bottom">▴</span>' : ""}
      </button>
    `;
  }

  return `
    <div class="mb-page">
      ${renderTopBar()}

      <div class="mb-hero">
        ${icon("crown", 26, COLORS.gold)}
        <h1 class="mb-hero-title">MYSTERY BOX</h1>
        <p class="mb-hero-sub">Відкрий бокс та отримай випадковий приз!</p>
      </div>

      <div class="mb-grid">${grid}</div>

      <div class="mb-ticket-note">
        ${icon("key", 14, "#8B4FE0")}
        <span>У тебе є ${state.tickets} ключі</span>
      </div>

      <button class="mb-open-btn" data-action="open" ${disabled ? "disabled" : ""}>
        ${icon("gift", 18)}
        <span>${label}</span>
        <span class="mb-open-btn-ticket">${icon("key", 13)} 1</span>
      </button>
    </div>
  `;
}

