function renderMissionCard(item, isBonus, missionId) {
  const rewardLabel = typeof item.reward === "number"
    ? `${item.reward} <span style="margin-left:2px;">RP</span>`
    : item.reward;
  const rewardIcon = typeof item.reward === "number" ? icon("coins", 12, "#B98A1E") : icon("key", 12, "#B98A1E");
  const isSelected = !isBonus && missionId && state.selectedMissions.has(missionId);
  const isConfirmed = !isBonus && missionId && state.confirmedMissions.has(missionId);
  const selectAttrs = !isBonus && missionId
    ? `data-action="select-mission" data-mission-id="${missionId}" data-label="${item.label.replace(/"/g, "&quot;")}"`
    : "";
  const cardClass = isBonus
    ? "mb-mission-bonus-card"
    : isConfirmed
      ? "mb-mission-card-confirmed"
      : isSelected
        ? "mb-mission-card-selected"
        : "";
  const iconName = isConfirmed ? "crown" : isSelected ? "check-circle-2" : (isBonus ? "sparkles" : "check");
  const iconColor = isConfirmed ? "#B98A1E" : isSelected ? "#2E8B57" : "#5638A6";
  return `
    <div class="mb-mission-card ${cardClass}" ${selectAttrs}>
      <div class="mb-mission-card-icon">${icon(iconName, 16, iconColor)}</div>
      <div class="mb-mission-card-label">${item.label}</div>
      <div class="mb-mission-card-reward">${rewardIcon} ${rewardLabel}</div>
      ${isConfirmed ? `<div class="mb-mission-confirmed-badge">${icon("badge-check", 12, "#B98A1E")} Підтверджено</div>` : ""}
    </div>
  `;
}

function renderMissionSection(section) {
  const cards = section.items
    .map((it, i) => renderMissionCard(it, false, `${section.id}-${i}`))
    .join("");
  const bonus = section.bonus ? renderMissionCard(section.bonus, true) : "";
  return `
    <div class="mb-mission-section">
      <div class="mb-mission-section-header">
        ${icon(section.icon, 17, "#E8BE4F")}
        <h3 class="mb-mission-section-title">${section.title}</h3>
      </div>
      <div class="mb-mission-list">${cards}${bonus}</div>
    </div>
  `;
}

